using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        var query = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue)
            query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            query = query.Where(a => a.StartTime <= to.Value);
        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).FirstOrDefaultAsync(a => a.Id == id);

    public async Task<List<Appointment>> GetAppointmentsForDateAsync(DateOnly date)
    {
        var start = date.ToDateTime(TimeOnly.MinValue);
        var end = date.ToDateTime(TimeOnly.MaxValue);
        return await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= start && a.StartTime <= end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<bool> IsSlotAvailableAsync(DateTime start, DateTime end, int? excludeId = null)
    {
        var query = db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime < end && a.EndTime > start);
        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);
        var count = await query.CountAsync();
        // Allow up to 3 concurrent appointments (3 vets)
        return count < 3;
    }

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        if (appointment.EndTime == default)
            appointment.EndTime = appointment.StartTime.AddMinutes(30);
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }
}
