using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync() =>
        await db.Invoices.Include(i => i.Owner).Include(i => i.Pet)
            .Include(i => i.Payments).Include(i => i.LineItems)
            .OrderByDescending(i => i.IssuedDate).ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.Owner).Include(i => i.Pet)
            .Include(i => i.LineItems).Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.LineItems.Sum(li => li.Quantity * li.UnitPrice);
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task UpdateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.LineItems.Sum(li => li.Quantity * li.UnitPrice);
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == payment.InvoiceId);
        invoice.PaidAmount = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
        invoice.Status = invoice.PaidAmount >= invoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? ownerId = null)
    {
        var query = db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Owner).AsQueryable();
        if (ownerId.HasValue)
            query = query.Where(p => p.Invoice.OwnerId == ownerId.Value);
        return await query.OrderByDescending(p => p.PaymentDate).ToListAsync();
    }
}
