@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private int durationMinutes = 30;
    private string? formError;
    private int availableSlots;

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetPetsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetAppointmentsForDateAsync(DateOnly.FromDateTime(selectedDate));
        await CalculateAvailability();
    }

    private async Task CalculateAvailability()
    {
        int slots = 0;
        var start = selectedDate.Date.AddHours(8);
        for (int i = 0; i < 20; i++) // 8am to 6pm, 30-min slots
        {
            var slotStart = start.AddMinutes(i * 30);
            var slotEnd = slotStart.AddMinutes(30);
            if (await AppointmentService.IsSlotAvailableAsync(slotStart, slotEnd))
                slots++;
        }
        availableSlots = slots;
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment { StartTime = selectedDate.Date.AddHours(9) };
        durationMinutes = 30;
        showForm = true;
        formError = null;
    }

    private void Reschedule(Appointment a)
    {
        editingAppointment = a;
        durationMinutes = (int)(a.EndTime - a.StartTime).TotalMinutes;
        showForm = true;
        formError = null;
    }

    private void CancelForm() { showForm = false; formError = null; }

    private async Task SaveAppointment()
    {
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);
        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime, 
            editingAppointment.Id == 0 ? null : editingAppointment.Id);
        if (!available)
        {
            formError = "This time slot is fully booked. Please select a different time.";
            return;
        }
        if (editingAppointment.Id == 0)
            await AppointmentService.CreateAppointmentAsync(editingAppointment);
        else
            await AppointmentService.UpdateAppointmentAsync(editingAppointment);
        showForm = false;
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointments();
    }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-primary"
    };
}
