using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    // Owners
    public async Task<List<Owner>> GetOwnersAsync() =>
        await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task<Owner> CreateOwnerAsync(Owner owner)
    {
        db.Owners.Add(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task UpdateOwnerAsync(Owner owner)
    {
        db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // Pets
    public async Task<List<Pet>> GetPetsAsync() =>
        await db.Pets.Include(p => p.Owner).Include(p => p.Treatments).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner).Include(p => p.Treatments.OrderByDescending(t => t.Date)).FirstOrDefaultAsync(p => p.Id == id);

    public async Task<Pet> CreatePetAsync(Pet pet)
    {
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task UpdatePetAsync(Pet pet)
    {
        db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task DeletePetAsync(int id)
    {
        var pet = await db.Pets.FindAsync(id);
        if (pet != null)
        {
            db.Pets.Remove(pet);
            await db.SaveChangesAsync();
        }
    }

    // Treatments
    public async Task<Treatment> AddTreatmentAsync(Treatment treatment)
    {
