            @foreach (var a in appointments)
            {
                <tr class="@GetStatusClass(a.Status)">
                    <td>@a.StartTime.ToString("HH:mm") - @a.EndTime.ToString("HH:mm")</td>
                    <td>@a.Pet.Name</td>
                    <td>@a.Pet.Owner.FullName</td>
                    <td>@a.Reason</td>
                    <td>@a.VetName</td>
                    <td><span class="badge @GetBadgeClass(a.Status)">@a.Status</span></td>
                    <td>
                        @if (a.Status == AppointmentStatus.Scheduled)
                        {
                            <button class="btn btn-sm btn-warning" @onclick="() => Reschedule(a)">Reschedule</button>
                            <button class="btn btn-sm btn-danger" @onclick="() => Cancel(a.Id)">Cancel</button>
                        }
                    </td>
