        showTreatmentForm = true;
    }

    private void EditTreatment(Treatment t)
    {
        editingTreatment = t;
        showTreatmentForm = true;
    }

    private void CancelTreatmentForm() => showTreatmentForm = false;

    private async Task SaveTreatment()
    {
        editingTreatment.PetId = Id;
        if (editingTreatment.Id == 0)
            await PatientService.AddTreatmentAsync(editingTreatment);
        else
            await PatientService.UpdateTreatmentAsync(editingTreatment);
        showTreatmentForm = false;
        await LoadPet();
    }

    private async Task DeleteTreatment(int id)
    {
        await PatientService.DeleteTreatmentAsync(id);
        await LoadPet();
    }
}

@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>Appointments</PageTitle>

<h3>Appointment Scheduling</h3>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:event="onchange" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">New Appointment</button>
    </div>
    <div class="col-md-6 d-flex align-items-end justify-content-end">
        <span class="badge bg-success me-2">Available slots: @availableSlots</span>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</h5>
            @if (!string.IsNullOrEmpty(formError))
            {
                <div class="alert alert-danger">@formError</div>
            }
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Start Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Duration (min)</label>
                        <input type="number" class="form-control" @bind="durationMinutes" min="15" step="15" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Vet</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.VetName" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.Status">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
