                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="CancelForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

<h5>Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h5>

@if (appointments.Count == 0)
{
    <div class="alert alert-info">No appointments for this date.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr>
        </thead>
