@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private int durationMinutes = 30;
    private string? formError;
    private int availableSlots;

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetPetsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetAppointmentsForDateAsync(DateOnly.FromDateTime(selectedDate));
        await CalculateAvailability();
    }

    private async Task CalculateAvailability()
    {
        int slots = 0;
        var start = selectedDate.Date.AddHours(8);
        for (int i = 0; i < 20; i++) // 8am to 6pm, 30-min slots
        {
            var slotStart = start.AddMinutes(i * 30);
            var slotEnd = slotStart.AddMinutes(30);
            if (await AppointmentService.IsSlotAvailableAsync(slotStart, slotEnd))
                slots++;
        }
        availableSlots = slots;
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment { StartTime = selectedDate.Date.AddHours(9) };
        durationMinutes = 30;
        showForm = true;
        formError = null;
    }

    private void Reschedule(Appointment a)
    {
        editingAppointment = a;
        durationMinutes = (int)(a.EndTime - a.StartTime).TotalMinutes;
        showForm = true;
        formError = null;
    }

    private void CancelForm() { showForm = false; formError = null; }

    private async Task SaveAppointment()
    {
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);
        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime, 
            editingAppointment.Id == 0 ? null : editingAppointment.Id);
        if (!available)
        {
            formError = "This time slot is fully booked. Please select a different time.";
            return;
        }
        if (editingAppointment.Id == 0)
            await AppointmentService.CreateAppointmentAsync(editingAppointment);
        else
            await AppointmentService.UpdateAppointmentAsync(editingAppointment);
        showForm = false;
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointments();
    }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-primary"
    };
}

@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject BillingService BillingService
@inject PatientService PatientService

<PageTitle>Billing</PageTitle>

<h3>Billing & Payments</h3>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5>Create Invoice</h5>
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Owner</label>
                        <select class="form-select" @bind="newInvoiceOwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Pet (optional)</label>
                        <select class="form-select" @bind="newInvoicePetId">
                            <option value="0">-- None --</option>
                            @foreach (var p in petsForOwner)
                            {
                                <option value="@p.Id">@p.Name</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Description</label>
                        <input type="text" class="form-control" @bind="newInvoiceDescription" />
                    </div>
                </div>

                <h6>Line Items</h6>
                <table class="table table-sm">
                    <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr></thead>
                    <tbody>
                        @for (int i = 0; i < lineItems.Count; i++)
                        {
                            var idx = i;
                            <tr>
                                <td><input type="text" class="form-control form-control-sm" @bind="lineItems[idx].Description" /></td>
                                <td><input type="number" class="form-control form-control-sm" style="width:80px" @bind="lineItems[idx].Quantity" min="1" /></td>
                                <td><input type="number" class="form-control form-control-sm" style="width:100px" @bind="lineItems[idx].UnitPrice" step="0.01" /></td>
                                <td>@((lineItems[idx].Quantity * lineItems[idx].UnitPrice).ToString("C"))</td>
                                <td><button class="btn btn-sm btn-danger" @onclick="() => lineItems.RemoveAt(idx)">×</button></td>
                            </tr>
                        }
                    </tbody>
                </table>
                <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="AddLineItem">+ Add Item</button>
                <div class="mt-2">
                    <strong>Total: @lineItems.Sum(li => li.Quantity * li.UnitPrice).ToString("C")</strong>
                </div>
                <div class="mt-2">
                    <button class="btn btn-primary" @onclick="SaveInvoice">Save Invoice</button>
                    <button class="btn btn-secondary ms-2" @onclick="() => showInvoiceForm = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    @if (showPaymentForm)
    {
        <div class="card mb-3 border-success">
            <div class="card-body">
                <h5>Process Payment for Invoice #@payingInvoice!.Id</h5>
                <p>Outstanding: @((payingInvoice!.TotalAmount - payingInvoice.PaidAmount).ToString("C"))</p>
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" @bind="paymentAmount" step="0.01" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="paymentReference" />
                    </div>
                    <div class="col-md-3 d-flex align-items-end">
                        <button class="btn btn-success" @onclick="ProcessPayment">Process</button>
                        <button class="btn btn-secondary ms-2" @onclick="() => showPaymentForm = false">Cancel</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <table class="table table-striped">
        <thead>
            <tr><th>#</th><th>Date</th><th>Owner</th><th>Pet</th><th>Total</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.IssuedDate.ToString("yyyy-MM-dd")</td>
                    <td>@inv.Owner.FullName</td>
                    <td>@(inv.Pet?.Name ?? "-")</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.PaidAmount.ToString("C")</td>
                    <td><span class="badge @GetInvoiceBadge(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status != InvoiceStatus.Paid && inv.Status != InvoiceStatus.Cancelled)
                        {
                            <button class="btn btn-sm btn-success" @onclick="() => ShowPayment(inv)">Pay</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (activeTab == "payments")
{
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var p in payments)
            {
                <tr>
                    <td>@p.PaymentDate.ToString("g")</td>
                    <td>@p.InvoiceId</td>
                    <td>@p.Invoice.Owner.FullName</td>
                    <td>@p.Amount.ToString("C")</td>
                    <td>@p.Method</td>
                    <td>@p.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = [];
    private List<Payment> payments = [];
    private List<Owner> owners = [];
    private List<Pet> petsForOwner = [];
    private bool showInvoiceForm, showPaymentForm;

    // New invoice fields
    private int newInvoiceOwnerId;
    private int newInvoicePetId;
    private string newInvoiceDescription = "";
    private List<InvoiceLineItem> lineItems = [];

    // Payment fields
    private Invoice? payingInvoice;
    private decimal paymentAmount;
    private PaymentMethod paymentMethod;
    private string paymentReference = "";

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        invoices = await BillingService.GetInvoicesAsync();
        payments = await BillingService.GetPaymentHistoryAsync();
        owners = await PatientService.GetOwnersAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoiceOwnerId = 0;
        newInvoicePetId = 0;
        newInvoiceDescription = "";
        lineItems = [new InvoiceLineItem()];
        showInvoiceForm = true;
        showPaymentForm = false;
    }

    private void AddLineItem() => lineItems.Add(new InvoiceLineItem());

    private async Task SaveInvoice()
    {
        if (newInvoiceOwnerId == 0) return;
        var invoice = new Invoice
        {
            OwnerId = newInvoiceOwnerId,
            PetId = newInvoicePetId == 0 ? null : newInvoicePetId,
            Description = newInvoiceDescription,
            IssuedDate = DateTime.Now,
            LineItems = lineItems.Where(li => !string.IsNullOrWhiteSpace(li.Description)).ToList()
        };
        await BillingService.CreateInvoiceAsync(invoice);
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPayment(Invoice inv)
    {
        payingInvoice = inv;
        paymentAmount = inv.TotalAmount - inv.PaidAmount;
        paymentMethod = PaymentMethod.Cash;
        paymentReference = "";
        showPaymentForm = true;
        showInvoiceForm = false;
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;
        var payment = new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference,
            PaymentDate = DateTime.Now
        };
        await BillingService.ProcessPaymentAsync(payment);
        showPaymentForm = false;
        await LoadData();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-primary"
    };
}

