@inject PatientService PatientService

<PageTitle>Patients</PageTitle>

<h3>Patient Records</h3>

<div class="row mb-3">
    <div class="col">
        <button class="btn btn-primary" @onclick="ShowAddOwner">
            <span class="bi bi-plus"></span> New Owner
        </button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">
            <span class="bi bi-plus"></span> New Pet
        </button>
    </div>
    <div class="col-auto">
        <input type="text" class="form-control" placeholder="Search..." @bind="searchTerm" @bind:event="oninput" />
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="CancelOwnerForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</h5>
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                        <ValidationMessage For="() => editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="editingPet.Species" />
                        <ValidationMessage For="() => editingPet.Species" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">-- Select --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="CancelPetForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Pet Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Age</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>@(pet.DateOfBirth.HasValue ? $"{DateOnly.FromDateTime(DateTime.Today).DayNumber - pet.DateOfBirth.Value.DayNumber:N0} days" : "Unknown")</td>
                <td>
                    <a href="/patients/@pet.Id" class="btn btn-sm btn-info">View</a>
                    <button class="btn btn-sm btn-warning" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-danger" @onclick="() => DeletePet(pet.Id)">Delete</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Owner> owners = [];
    private List<Pet> pets = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        owners = await PatientService.GetOwnersAsync();
        pets = await PatientService.GetPetsAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; showPetForm = false; }
    private void ShowAddPet() { editingPet = new(); showPetForm = true; showOwnerForm = false; }
    private void CancelOwnerForm() => showOwnerForm = false;
    private void CancelPetForm() => showPetForm = false;

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            await PatientService.CreateOwnerAsync(editingOwner);
        else
            await PatientService.UpdateOwnerAsync(editingOwner);
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.Id == 0)
            await PatientService.CreatePetAsync(editingPet);
        else
            await PatientService.UpdatePetAsync(editingPet);
        showPetForm = false;
        await LoadData();
    }

    private async Task DeletePet(int id)
    {
        await PatientService.DeletePetAsync(id);
        await LoadData();
    }
}
